class Solution:
    def findRelativeRanks(self, score):
        n = len(score)
        ans = [''] * n
        order = sorted(range(n), key=lambda i: -score[i])
        labels = {0: 'Gold Medal', 1: 'Silver Medal', 2: 'Bronze Medal'}
        for place, idx in enumerate(order):
            ans[idx] = labels.get(place, str(place + 1))
        return ans

